    public static final Set<Sleutel<?>> REKEN_HOOFD_SLEUTEL_PRE_2019 = ImmutableSet
            .of(SleutelCategorie.INSTANCE, SleutelWerkgeversCategorie.INSTANCE, SleutelWerknemersKengetal.INSTANCE, SleutelPensioenStelsel.INSTANCE);

    public static final Set<Sleutel<?>> REKEN_HOOFD_SLEUTEL = ImmutableSet
            .of(SleutelCategorie.NVT_INSTANCE, SleutelWerkgeversCategorie.INSTANCE, SleutelWerknemersKengetal.INSTANCE, SleutelPensioenStelsel.INSTANCE);

    private static final Set<RekenBedragType> BEDRAG_TYPES_ACHTERSTAL =
            Sets.immutableEnumSet(RekenBedragType.BELASTBAAR_ACHTERSTAL, RekenBedragType.DIFF_BELASTBAAR_ACHTERSTAL,
                    RekenBedragType.BEDRIJFSVOORHEFFING_ACHTERSTAL, RekenBedragType.VRIJSTELLING_BELASTBAAR);

    private static final Integer FICTIEVE_DMFA_AANGIFTEID_DOELGROEP_VERM = 99_999_999;

    private static final int LOONCODE_MOBILITEITS_BUDGET = 29;

    public static Set<Sleutel<?>> bepaalRekenHoofdSleutel(LocalDate beginDatum) {
        if (beginDatum.getYear() >= 2019) {
            return REKEN_HOOFD_SLEUTEL;
        } else {
            return REKEN_HOOFD_SLEUTEL_PRE_2019;
        }
    }

    public List<RekenHoofd> maakRekenResultaten(
            RekenContext mainContext, List<RekenHoofd> bestaandeResultaten,
            OpslaanNulResultaten strategieNulResultaten) {
        ListMultimap<Integer, RekenHoofd> opdrachtIdToRekenHoofden = RekenResultaatUtil.mapOpdrachtIdToRekenHoofden(bestaandeResultaten);

        Persoon persoon = mainContext.getUnchecked(RekenChainKey.PERSOON_KEY);
        RekenTijd rekenTijd = mainContext.getUnchecked(RekenChainKey.REKENTIJD_KEY);
        int fiscaalJaar = mainContext.getInteger(RekenChainKey.FISCAAL_JAAR_KEY);
        Rekenmodus rekenModus = mainContext.getUnchecked(RekenChainKey.REKENMODUS_KEY);
        PersoonsDataManager dataManager = mainContext.getUnchecked(RekenChainKey.PERSOONSDATA_MANAGER_KEY);
        Persoon persoonKwartaalSimpel = dataManager.getPersoonKwartaalSimpel();
        boolean astBvPerFiscaalJaar = RekenTools.heeftOpdrachtBedrijfsvoorheffingVrijwilligeBrandweer(persoonKwartaalSimpel);
        Map<Integer, Boolean> opdrachtIdToNulResultaat =
                mapOpdrachtIdToNullResultaat(persoon, strategieNulResultaten, opdrachtIdToRekenHoofden, dataManager, rekenTijd);

        LoonElementManager manager = mainContext.getUnchecked(RekenChainKey.LOONELEMENT_MANAGER_KEY);

        List<RekenHoofd> rekenHoofden = new ArrayList<>();
        for (Opdracht opdracht : persoon.getOpdrachten()) {
            RekenContext opdrachtContext = mainContext.getOpdrachtContext(opdracht);
            Opper opper = opdrachtContext.getUnchecked(RekenChainKey.OPPER_LAATSTE_GEGEVENS_KEY);
            Rekengroep rekenGroep = Rekengroep.getByCode(opper.getWeddeBerekening().getRekenGroep());
            List<RekenHoofd> bestaandeOpdrachtResultaten = opdrachtIdToRekenHoofden.get(opdracht.getId());
            ListMultimap<RekenHoofdKey, RekenHoofd> mapRekenHoofdKeyToRekenHoofden = RekenResultaatUtil.mapRekenHoofdKeyToRekenHoofden(bestaandeOpdrachtResultaten);

            SleutelSamenNemer aggregator = new SleutelSamenNemer();
            List<SleutelGegevens> aggregaten = aggregator.neemSamenVoorSleutel(opdracht, bepaalRekenHoofdSleutel(rekenTijd.beginDatum));

            ListMultimap<RekenHoofdKey, SleutelGegevens> mapRekenHoofdKeyToSleutelGegevens = RekenResultaatUtil.mapRekenHoofdKeyToSleutelGegevens(aggregaten, rekenTijd);

            Set<RekenHoofdKey> rekenHoofdKeys = new TreeSet<>();
            rekenHoofdKeys.addAll(mapRekenHoofdKeyToRekenHoofden.keySet());
            rekenHoofdKeys.addAll(mapRekenHoofdKeyToSleutelGegevens.keySet());
            boolean nulResultaat = opdrachtIdToNulResultaat.get(opdracht.getId());
            boolean vorigKwartaal = dataManager.isOpdrachtInOpzegOpEerstDagKwartaal(opdracht);
            for (RekenHoofdKey key : rekenHoofdKeys) {
                rekenHoofden.addAll(
                        maakRekenResultatenVoorRekenHoofdKey(key, mapRekenHoofdKeyToSleutelGegevens, mapRekenHoofdKeyToRekenHoofden, manager,
                                fiscaalJaar, opdracht, rekenModus, rekenGroep, vorigKwartaal, rekenTijd, nulResultaat, false, astBvPerFiscaalJaar));
                //Nogmaals voor resultaten die op een fictief dmfaAangifteId moeten komen.
                List<RekenHoofd> temp =
                        maakRekenResultatenVoorRekenHoofdKey(key, mapRekenHoofdKeyToSleutelGegevens, mapRekenHoofdKeyToRekenHoofden, manager,
                                fiscaalJaar, opdracht, rekenModus, rekenGroep, vorigKwartaal, rekenTijd, nulResultaat, true, astBvPerFiscaalJaar);
                temp.forEach(x -> x.setDmfapplAangifteId(FICTIEVE_DMFA_AANGIFTEID_DOELGROEP_VERM));
                rekenHoofden.addAll(temp);
            }
        }

        rekenHoofden = cleanNulResultaten(rekenHoofden, opdrachtIdToNulResultaat);

        overnemenRekenInfoBijTegenBoekingBlo(rekenHoofden);

        return rekenHoofden;
    }

    private List<RekenHoofd> maakRekenResultatenVoorRekenHoofdKey(
            RekenHoofdKey key,
            ListMultimap<RekenHoofdKey, SleutelGegevens> mapRekenHoofdKeyToSleutelGegevens, ListMultimap<RekenHoofdKey, RekenHoofd> mapRekenHoofdKeyToRekenHoofden,
            LoonElementManager manager, Integer fiscaalJaar, Opdracht opdracht, Rekenmodus rekenModus, Rekengroep rekenGroep,
            boolean vorigKwartaal, RekenTijd rekenTijd, boolean nulResultaat, boolean afzonderenOpFicitieveDmfaAangifteId, boolean astBvPerFiscaalJaar) {
        List<RekenHoofd> rekenHoofden = new ArrayList<>();
        List<SleutelGegevens> gegevens = mapRekenHoofdKeyToSleutelGegevens.get(key);
        List<RekenHoofd> bestaandeRekenHoofdKeyResultaten = mapRekenHoofdKeyToRekenHoofden.get(key);
        SetMultimap<LocalDate, RekenLijn> beslagDatum2Lijnen =
                vormRekenLijnen(gegevens, manager, bestaandeRekenHoofdKeyResultaten, fiscaalJaar, rekenTijd, nulResultaat,
                        afzonderenOpFicitieveDmfaAangifteId, astBvPerFiscaalJaar);
        SetMultimap<LocalDate, RekenOverdracht> beslagDatum2Overdrachten =
                vormRekenOverdrachten(opdracht, gegevens, manager, bestaandeRekenHoofdKeyResultaten, rekenTijd, afzonderenOpFicitieveDmfaAangifteId);
        Set<LocalDate> beslagDatums = new HashSet<>(beslagDatum2Lijnen.keySet());
        beslagDatums.addAll(beslagDatum2Overdrachten.keySet());
        for (LocalDate beslagDatum : beslagDatums) {
            Set<RekenLijn> lijnen = beslagDatum2Lijnen.get(beslagDatum);
            Set<RekenOverdracht> overdrachten = beslagDatum2Overdrachten.get(beslagDatum);
            if (!lijnen.isEmpty() || !overdrachten.isEmpty()) {
                RekenHoofd rekenHoofd = RekenResultaatUtil.maakRekenHoofd(opdracht, key, rekenModus, rekenGroep, rekenTijd, fiscaalJaar, beslagDatum, vorigKwartaal);
                rekenHoofd.setRekenLijnen(lijnen);
                rekenHoofd.setRekenOverdrachten(overdrachten);
                rekenHoofden.add(rekenHoofd);
            }
        }
        return rekenHoofden;
    }

    private Map<Integer, Boolean> mapOpdrachtIdToNullResultaat(
            Persoon persoon, OpslaanNulResultaten strategieNulResultaten,
            ListMultimap<Integer, RekenHoofd> opdrachtIdToRekenHoofden, PersoonsDataManager dataManager, RekenTijd rekenTijd) {
        Map<Integer, Boolean> opdrachtIdToNulResultaat = new HashMap<>();
        for (Opdracht opdracht : persoon.getOpdrachten()) {
            List<NlpPrestatie> prestaties = dataManager.findPrestaties(opdracht, rekenTijd.eindDatum);
            opdrachtIdToNulResultaat
                    .put(opdracht.getId(), beslissingNulResultaat(opdracht.getId(), strategieNulResultaten, opdrachtIdToRekenHoofden, prestaties));
        }
        return opdrachtIdToNulResultaat;
    }

    private boolean beslissingNulResultaat(
            Integer opdrachtId, OpslaanNulResultaten strategieNulResultaten,
            ListMultimap<Integer, RekenHoofd> opdrachtIdToRekenHoofden, List<NlpPrestatie> prestaties) {
        List<RekenHoofd> bestaanden = opdrachtIdToRekenHoofden.get(opdrachtId);
        boolean nulResultaat;
        if (strategieNulResultaten == OpslaanNulResultaten.LEGE_RESULTATEN_OPSLAAN) {
            nulResultaat = !prestaties.isEmpty() && bestaanden.isEmpty();
        } else if (strategieNulResultaten == OpslaanNulResultaten.WIJZIGING_KALENDER) {
            nulResultaat = versePrestatiesAanwezig(bestaanden, prestaties);
        } else {
            nulResultaat = false;
        }
        return nulResultaat;
    }

    private boolean versePrestatiesAanwezig(List<RekenHoofd> bestaandeResultaten, List<NlpPrestatie> prestaties) {
        LocalDateTime recentsteBerekening =
                bestaandeResultaten.stream().map(RekenHoofd::getRekenTijdstip).max(LocalDateTime::compareTo).orElse(TimeTools.getMinimumTijdstip());
        LocalDateTime recentstePrestatie =
                prestaties.stream().map(NlpPrestatie::getIngaveTijdstip).max(LocalDateTime::compareTo).orElse(TimeTools.getMinimumTijdstip());

        return recentsteBerekening.isBefore(recentstePrestatie);
    }

    private void overnemenRekenInfoBijTegenBoekingBlo(List<RekenHoofd> hoofden) {
        Multimap<Integer, RekenLijn> rekenLijnMap = ArrayListMultimap.create();
        Multimap<Integer, RekenInfo> rekenInfoMap = ArrayListMultimap.create();
        for (RekenHoofd hoofd : hoofden) {
            for (RekenLijn lijn : hoofd.getRekenLijnen()) {
                if (lijn.getAardKodeExtensie().behoortTotGroep(LooncodeGroepKeyStrings.BESLAG_OP_LOON_KEY)) {
                    if (lijn.getTypeBoeking() == AardRekenelement.TEGENBOEKING && lijn.getRekenInfos().isEmpty()) {
                        rekenLijnMap.put(lijn.getAardKodeExtensie().getId(), lijn);
                    } else {
                        rekenInfoMap.putAll(lijn.getAardKodeExtensie().getId(), lijn.getRekenInfos());
                    }
                }
            }
        }
        for (Integer akeId : rekenLijnMap.keySet()) {
            Collection<RekenLijn> lijnen = rekenLijnMap.get(akeId);
            Collection<RekenInfo> infos = rekenInfoMap.get(akeId);
            for (RekenLijn lijn : lijnen) {
                Set<RekenInfo> rekenInfos = RekenInfoComparator.createSortedSet();
                infos.stream().map(RekenResultaatUtil::maakRekenInfo).forEach(rekenInfos::add);
                lijn.setRekenInfos(rekenInfos);
            }
        }
    }

    private SetMultimap<LocalDate, RekenLijn> vormRekenLijnen(
            List<SleutelGegevens> aggregaat, LoonElementManager manager,
            List<RekenHoofd> bestaandeOpdrachtResultaten, int fiscaalJaar, RekenTijd rekenTijd, boolean nulResultaat,
            boolean afzonderenOpFicitieveDmfaAangifteId, boolean astBvPerFiscaalJaar) {
        MoneyTable<RekenLijnKey, RekenBedragType> lijn2BedragenMap = HashMoneyTable.create();
        Table<RekenLijnKey, RekenInfoKey, Object> lijn2InfosMap = HashBasedTable.create();
        MoneyTable<RekenLijnKey, RekenBedragType> lijn2ToegepasteTussenkomstMap = HashMoneyTable.create();
        Set<RekenLijnKey> nulResultaatSet = new HashSet<>();
        Set<RekenLijnKey> tegenBoekingSet =
                vormTegenBoekingSet(aggregaat, manager, bestaandeOpdrachtResultaten, rekenTijd, afzonderenOpFicitieveDmfaAangifteId);

        bestaandeResultatenTegenBoeken(bestaandeOpdrachtResultaten, lijn2BedragenMap, lijn2ToegepasteTussenkomstMap, fiscaalJaar,
                rekenTijd.beslagDatum, afzonderenOpFicitieveDmfaAangifteId, astBvPerFiscaalJaar);
        nieuweResultatenBoeken(aggregaat, manager, rekenTijd.rekenPeriode, lijn2BedragenMap, lijn2ToegepasteTussenkomstMap, lijn2InfosMap,
                rekenTijd.isApo, rekenTijd.beslagDatum, nulResultaatSet, nulResultaat, afzonderenOpFicitieveDmfaAangifteId);
        return vormRekenLijnen(lijn2BedragenMap, lijn2ToegepasteTussenkomstMap, lijn2InfosMap, tegenBoekingSet, nulResultaatSet);
    }

    private Set<RekenLijnKey> vormTegenBoekingSet(
            List<SleutelGegevens> aggregaten, LoonElementManager manager, List<RekenHoofd> bestaandeOpdrachtResultaten,
            RekenTijd rekenTijd, boolean afzonderenOpFicitieveDmfaAangifteId) {
        Set<RekenLijnKey> gebruiktInVorige = bepaalGebruikteRekenLijnen(bestaandeOpdrachtResultaten, rekenTijd.beslagDatum);
        Set<RekenLijnKey> gebruiktInHuidige =
                bepaalHuidigeRekenLijnen(aggregaten, manager, rekenTijd.rekenPeriode, rekenTijd.isApo, rekenTijd.beslagDatum,
                        afzonderenOpFicitieveDmfaAangifteId);
        Set<RekenLijnKey> tegenBoekingSet = new HashSet<>(gebruiktInVorige);
        tegenBoekingSet.removeAll(gebruiktInHuidige);
        return tegenBoekingSet;
    }

    private Set<RekenLijnKey> bepaalHuidigeRekenLijnen(
            List<SleutelGegevens> aggregaten, LoonElementManager manager, LocalDateInterval rekenPeriode,
            boolean isApo, LocalDate defaultBeslagDatum, boolean afzonderenOpFicitieveDmfaAangifteId) {
        Set<RekenLijnKey> keys = new HashSet<>();
        for (SleutelGegevens aggregaat : aggregaten) {
            for (Opper opper : aggregaat.getOppers()) {
                Collection<LoonElement> opperElementen = manager.getOpperElementen(opper).stream()
                        .filter(x -> afzonderenOpFicitieveDmfaAangifteId == LoonCodeTools.isFictieveAkeDoelgroepVerminderingen(x.getAardKodeExtensie()))
                        .collect(Collectors.toList());
                for (LoonElement element : opperElementen) {
                    LocalDateInterval actualInterval = limiteerTotOpper(rekenPeriode, opper, isApo);
                    LocalDate beslagDatum = element.getBeslagDatum();
                    if (beslagDatum == null) {
                        beslagDatum = defaultBeslagDatum;
                    }
                    RekenLijnKey key = new RekenLijnKey(element.getAardKodeExtensie(), actualInterval, element.getRegimeBv(), beslagDatum,
                            element.getReferentieJaar());

                    for (Entry<ContextKey, Object> entry : element.getProperties().entrySet()) {
                        if (entry.getKey() instanceof MoneyKey && entry.getKey().isTeBewaren() && (
                                entry.getKey().equals(RekenBrutoKey.BRUTO_MAANDLOON_KEY) || entry.getKey()
                                        .equals(RekenBrutoKey.BASIS_SOCIALE_INHOUDINGEN_KEY) || (
                                        element.getAardKodeExtensie().getAard().equals(AardKodeExt.I_KODE_EXT.getCode()) && entry.getKey()
                                                .equals(RekenNettoKey.NETTO_KEY)))) {
                            MoneyKey moneyKey = (MoneyKey) entry.getKey();
                            Money bedrag = (Money) entry.getValue();
                            RekenLijnKey finalKey = key;
                            if (moneyKey.getAfwijkendRegime() != null) {
                                finalKey = new RekenLijnKey(key, moneyKey.getAfwijkendRegime());
                            }
                            if (bedrag.signum() != 0) {
                                keys.add(finalKey);
                            }
                        }
                    }
                }
            }
        }
        return keys;
    }

    private Set<RekenLijnKey> bepaalGebruikteRekenLijnen(List<RekenHoofd> bestaandeOpdrachtResultaten, LocalDate defaultBeslagDatum) {
        Set<RekenLijnKey> keys = new HashSet<>();
        Set<RekenHoofd> sorted = RekenHoofdComparator.createSortedSet(bestaandeOpdrachtResultaten);
        for (RekenHoofd hoofd : sorted) {
            for (RekenLijn oudeLijn : hoofd.getRekenLijnen()) {
                LocalDate beslagDatum = null;
                if (oudeLijn.getAardKodeExtensie().behoortTotGroep(LooncodeGroepKeyStrings.BESLAG_OP_LOON_KEY)) {
                    beslagDatum = hoofd.getBeslagDatum();
                }
                if (beslagDatum == null) {
                    beslagDatum = defaultBeslagDatum;
                }
                RekenLijnKey key = new RekenLijnKey(oudeLijn, beslagDatum);
                keys.add(key);

            }
        }
        return keys;
    }

    private SetMultimap<LocalDate, RekenLijn> vormRekenLijnen(
            MoneyTable<RekenLijnKey, RekenBedragType> lijn2BedragenMap,
            MoneyTable<RekenLijnKey, RekenBedragType> lijn2ToegepasteTussenkomstMap, Table<RekenLijnKey, RekenInfoKey, Object> lijn2InfosMap,
            Set<RekenLijnKey> tegenBoekingSet, Set<RekenLijnKey> nulResultaatSet) {
        SetMultimap<LocalDate, RekenLijn> beslagDatum2Lijnen = TreeMultimap.create(Ordering.natural(), Ordering.arbitrary());
        for (RekenLijnKey key : lijn2BedragenMap.rowKeySet()) {
            Map<RekenBedragType, Money> nieuwBedragen = lijn2BedragenMap.row(key);
            Set<RekenBedrag> rekenBedragen = vormRekenBedragen(nieuwBedragen, key.getAardKodeExtensie(), nulResultaatSet.contains(key));
            Map<RekenBedragType, Money> nieuwToegepasten = lijn2ToegepasteTussenkomstMap.row(key);
            Set<ToegepasteTussenkomst> toegepasten = RekenResultaatUtil.vormToegepasteTussenkomsten(nieuwToegepasten);
            //TODO wat als rekenBedragen leeg en toegepasten niet leeg
            if (!rekenBedragen.isEmpty()) {
                Map<RekenInfoKey, Object> infos = lijn2InfosMap.row(key);
                Set<RekenInfo> rekenInfos = RekenResultaatUtil.vormRekenInfos(infos);
                AardRekenelement typeBoeking = tegenBoekingSet.contains(key) ? AardRekenelement.TEGENBOEKING : AardRekenelement.SALDO;
                RekenLijn lijn = RekenResultaatUtil.maakRekenLijn(key, rekenBedragen, toegepasten, rekenInfos, typeBoeking);
                beslagDatum2Lijnen.put(key.getBeslagDatum(), lijn);
            }
        }
        return beslagDatum2Lijnen;
    }

    private Set<RekenBedrag> vormRekenBedragen(Map<RekenBedragType, Money> nieuwBedragen, AardKodeExtensie aardKodeExtensie, boolean nulResultaat) {
        Set<RekenBedrag> rekenBedragen = new HashSet<>();
        for (Entry<RekenBedragType, Money> entry : nieuwBedragen.entrySet()) {
            if (entry.getValue().signum() != 0 || rekenBedragZeroOpslaan(aardKodeExtensie, entry.getKey())) {
                RekenBedrag rekenBedrag = RekenResultaatUtil.maakRekenBedrag(entry.getKey(), entry.getValue());
                rekenBedragen.add(rekenBedrag);
            }
        }
        if (rekenBedragen.isEmpty() && nulResultaat) {
            RekenBedragType defaultType = aardKodeExtensie.getAard().equals(AardKodeExt.I_KODE_EXT.getCode()) ? RekenBedragType.NETTO : RekenBedragType.BRUTO_MAANDLOON;
            RekenBedrag rekenBedrag = RekenResultaatUtil.maakRekenBedrag(defaultType, Money.ZERO);
            rekenBedragen.add(rekenBedrag);
        }
        return rekenBedragen;
    }

    private boolean rekenBedragZeroOpslaan(AardKodeExtensie aardKodeExtensie, RekenBedragType key) {
        return aardKodeExtensie.getCode() == LOONCODE_MOBILITEITS_BUDGET && key == RekenBedragType.BRUTO_MAANDLOON;
    }

    private SetMultimap<LocalDate, RekenOverdracht> vormRekenOverdrachten(
            Opdracht opdracht, List<SleutelGegevens> aggregaten, LoonElementManager manager,
            List<RekenHoofd> bestaandeOpdrachtResultaten, RekenTijd rekenTijd, boolean afzonderenOpFicitieveDmfaAangifteId) {
        MoneyMap<RegimeRekenBedragTypeKey> overdrachtBedragenMap = new HashMoneyMap<>();

        SetMultimap<LocalDate, RekenOverdracht> beslagDatum2Overdrachten = TreeMultimap.create(Ordering.natural(), Ordering.arbitrary());
        if (!afzonderenOpFicitieveDmfaAangifteId) {
            bestaandeResultatenTegenBoeken(bestaandeOpdrachtResultaten, overdrachtBedragenMap);
            nieuweResultatenBoeken(aggregaten, manager, overdrachtBedragenMap);
            beslagDatum2Overdrachten = vormRekenOverdrachten(opdracht, rekenTijd, overdrachtBedragenMap);
        }
        return beslagDatum2Overdrachten;
    }

    private SetMultimap<LocalDate, RekenOverdracht> vormRekenOverdrachten(
            Opdracht opdracht, RekenTijd rekenTijd,
            MoneyMap<RegimeRekenBedragTypeKey> overdrachtBedragenMap) {
        SetMultimap<LocalDate, RekenOverdracht> beslagDatum2Overdrachten = TreeMultimap.create(Ordering.natural(), Ordering.arbitrary());
        for (Entry<RegimeRekenBedragTypeKey, Money> entry : overdrachtBedragenMap.entrySet()) {
            if (entry.getValue().signum() != 0) {
                RegimeRekenBedragTypeKey key = entry.getKey();
                RekenOverdracht overdracht = RekenResultaatUtil.maakRekenOverdracht(opdracht, rekenTijd, key.getRegimeBv(), key.getRekenBedragType(), entry.getValue());

                beslagDatum2Overdrachten.put(rekenTijd.beslagDatum, overdracht);
            }
        }
        return beslagDatum2Overdrachten;
    }

    private boolean checkBedragFiscaalJaarGebonden(RekenBedrag bedrag, RekenHoofd hoofd, Integer fiscaalJaar, boolean astBvPerFiscaalJaar) {
        return !((BEDRAG_TYPES_ACHTERSTAL.contains(bedrag.getBedragType())) && (!hoofd.getFiscaalJaar().equals(fiscaalJaar) || !astBvPerFiscaalJaar));
    }

    private void bestaandeResultatenTegenBoeken(
            List<RekenHoofd> bestaandeOpdrachtResultaten,
            MoneyTable<RekenLijnKey, RekenBedragType> lijn2BedragenMap, MoneyTable<RekenLijnKey, RekenBedragType> lijn2ToegepasteTussenkomstMap,
            Integer fiscaalJaar, LocalDate defaultBeslagDatum, boolean afzonderenOpFicitieveDmfaAangifteId, boolean astBvPerFiscaalJaar) {
        for (RekenHoofd hoofd : bestaandeOpdrachtResultaten) {
            for (RekenLijn oudeLijn : hoofd.getRekenLijnen()) {
                rekenLijnTegenBoeken(lijn2BedragenMap, lijn2ToegepasteTussenkomstMap, fiscaalJaar, defaultBeslagDatum,
                        afzonderenOpFicitieveDmfaAangifteId, hoofd, oudeLijn, astBvPerFiscaalJaar);
            }
        }
    }

    private void rekenLijnTegenBoeken(
            MoneyTable<RekenLijnKey, RekenBedragType> lijn2BedragenMap, MoneyTable<RekenLijnKey, RekenBedragType> lijn2ToegepasteTussenkomstMap,
            Integer fiscaalJaar, LocalDate defaultBeslagDatum, boolean afzonderenOpFicitieveDmfaAangifteId, RekenHoofd hoofd, RekenLijn oudeLijn,
            boolean astBvPerFiscaalJaar) {
        if (afzonderenOpFicitieveDmfaAangifteId == LoonCodeTools.isFictieveAkeDoelgroepVerminderingen(oudeLijn.getAardKodeExtensie())) {
            LocalDate beslagDatum = null;
            if (oudeLijn.getAardKodeExtensie().behoortTotGroep(LooncodeGroepKeyStrings.BESLAG_OP_LOON_KEY)) {
                beslagDatum = hoofd.getBeslagDatum();
            }
            if (beslagDatum == null) {
                beslagDatum = defaultBeslagDatum;
            }
            RekenLijnKey key = new RekenLijnKey(oudeLijn, beslagDatum);
            for (RekenBedrag oudBedrag : oudeLijn.getRekenBedragen()) {
                if (checkBedragFiscaalJaarGebonden(oudBedrag, hoofd, fiscaalJaar, astBvPerFiscaalJaar)) {
                    lijn2BedragenMap.addToMoney(key, oudBedrag.getBedragType(), oudBedrag.getBedrag().negate());
                }
            }
            for (ToegepasteTussenkomst toegepast : oudeLijn.getToegepasteTussenkomsten()) {
                lijn2ToegepasteTussenkomstMap.addToMoney(key, toegepast.getBedragType(), toegepast.getBedrag().negate());
            }
        }
    }

    private void bestaandeResultatenTegenBoeken(
            List<RekenHoofd> bestaandeOpdrachtResultaten,
            MoneyMap<RegimeRekenBedragTypeKey> overdrachtBedragenMap) {
        for (RekenHoofd hoofd : bestaandeOpdrachtResultaten) {
            for (RekenOverdracht oudeOverdracht : hoofd.getRekenOverdrachten()) {
                RegimeRekenBedragTypeKey key = new RegimeRekenBedragTypeKey(oudeOverdracht.getRegimeBv(), oudeOverdracht.getBedragType());
                overdrachtBedragenMap.addToMoney(key, oudeOverdracht.getBedrag().negate());
            }
        }
    }

    private void nieuweResultatenBoeken(
            List<SleutelGegevens> aggregaten, LoonElementManager manager, LocalDateInterval rekenPeriode,
            MoneyTable<RekenLijnKey, RekenBedragType> lijn2BedragenMap, MoneyTable<RekenLijnKey, RekenBedragType> lijn2ToegepasteTussenkomstMap,
            Table<RekenLijnKey, RekenInfoKey, Object> lijn2InfosMap, boolean isApo, LocalDate defaultBeslagDatum, Set<RekenLijnKey> nulResultaatSet,
            boolean nulResultaat, boolean afzonderenOpFicitieveDmfaAangifteId) {
        for (SleutelGegevens aggregaat : aggregaten) {
            for (Opper opper : aggregaat.getOppers()) {
                nieuweResultatenOpperBoeken(manager, rekenPeriode, lijn2BedragenMap, lijn2ToegepasteTussenkomstMap, lijn2InfosMap, isApo, defaultBeslagDatum,
                        nulResultaatSet, nulResultaat,
                        afzonderenOpFicitieveDmfaAangifteId, opper);
            }
        }
    }

    private void nieuweResultatenOpperBoeken(
            LoonElementManager manager, LocalDateInterval rekenPeriode, MoneyTable<RekenLijnKey, RekenBedragType> lijn2BedragenMap,
            MoneyTable<RekenLijnKey, RekenBedragType> lijn2ToegepasteTussenkomstMap, Table<RekenLijnKey, RekenInfoKey, Object> lijn2InfosMap, boolean isApo,
            LocalDate defaultBeslagDatum, Set<RekenLijnKey> nulResultaatSet, boolean nulResultaat, boolean afzonderenOpFicitieveDmfaAangifteId, Opper opper) {
        Collection<LoonElement> opperElementen = manager.getOpperElementen(opper).stream()
                .filter(x -> afzonderenOpFicitieveDmfaAangifteId == LoonCodeTools.isFictieveAkeDoelgroepVerminderingen(x.getAardKodeExtensie()))
                .collect(Collectors.toList());
        for (LoonElement element : opperElementen) {
            LocalDateInterval actualInterval = limiteerTotOpper(rekenPeriode, opper, isApo);
            LocalDate beslagDatum = element.getBeslagDatum();
            if (beslagDatum == null) {
                beslagDatum = defaultBeslagDatum;
            }
            RekenLijnKey key = new RekenLijnKey(element.getAardKodeExtensie(), actualInterval, element.getRegimeBv(), beslagDatum,
                    element.getReferentieJaar());
            BigDecimal aanstelling = opper.getRszppo().getAanstelling();
            if (aanstelling.signum() != 0 && !aanstelling.equals(BigDecimal.valueOf(9999)) && nulResultaat) {
                nulResultaatSet.add(key);
            }
            for (Entry<ContextKey, Object> entry : element.getProperties().entrySet()) {
                nieuweResultatenEntryBoeken(lijn2BedragenMap, lijn2ToegepasteTussenkomstMap, lijn2InfosMap, key, entry);
            }
        }
    }

    private void nieuweResultatenEntryBoeken(
            MoneyTable<RekenLijnKey, RekenBedragType> lijn2BedragenMap, MoneyTable<RekenLijnKey, RekenBedragType> lijn2ToegepasteTussenkomstMap,
            Table<RekenLijnKey, RekenInfoKey, Object> lijn2InfosMap, RekenLijnKey key, Entry<ContextKey, Object> entry) {
        if (entry.getKey() instanceof MoneyKey && (entry.getKey().isTeBewaren() || entry.getKey() instanceof OnthoudTussenkomstKey)) {
            MoneyKey moneyKey = (MoneyKey) entry.getKey();
            RekenBedragType bedragType = RekenTools.moneyKeyToBedragType(moneyKey);
            RekenLijnKey finalKey = key;
            if (moneyKey.getAfwijkendRegime() != null) {
                finalKey = new RekenLijnKey(key, moneyKey.getAfwijkendRegime());
            }
            if (entry.getKey() instanceof OnthoudTussenkomstKey) {
                lijn2ToegepasteTussenkomstMap.addToMoney(finalKey, bedragType, (Money) entry.getValue());
            } else {
                lijn2BedragenMap.addToMoney(finalKey, bedragType, (Money) entry.getValue());
            }
        } else {
            if (entry.getKey() instanceof RekenInfoKey && entry.getKey().isTeBewaren() && entry.getValue() != null) {
                RekenInfoKey infoType = (RekenInfoKey) entry.getKey();
                lijn2InfosMap.put(key, infoType, entry.getValue());
            }
        }
    }

    private void nieuweResultatenBoeken(List<SleutelGegevens> aggregaten, LoonElementManager manager, MoneyMap<RegimeRekenBedragTypeKey> overdrachtBedragenMap) {
        for (SleutelGegevens aggregaat : aggregaten) {
            for (Opper opper : aggregaat.getOppers()) {
                for (LoonElement element : manager.getOpperElementen(opper)) {
                    nieuweResultatenLoonElementBoeken(overdrachtBedragenMap, element);
                }
            }
        }
    }

    private void nieuweResultatenLoonElementBoeken(MoneyMap<RegimeRekenBedragTypeKey> overdrachtBedragenMap, LoonElement element) {
        LnedefRegBv regime = element.getRegimeBv();
        for (Entry<ContextKey, Object> entry : element.getProperties().entrySet()) {
            if (entry.getKey() instanceof OverdrachtKey) {
                MoneyKey moneyKey = ((OverdrachtKey) entry.getKey()).getBasisKey();
                RekenBedragType bedragType = RekenTools.moneyKeyToBedragType(moneyKey);

                LnedefRegBv finalRegime;
                if (moneyKey instanceof RekenBvKey) {
                    finalRegime = moneyKey.getAfwijkendRegime() == null ? regime : moneyKey.getAfwijkendRegime();
                } else {
                    finalRegime = LnedefRegBv.NVT;
                }
                RegimeRekenBedragTypeKey key = new RegimeRekenBedragTypeKey(finalRegime, bedragType);
                overdrachtBedragenMap.addToMoney(key, (Money) entry.getValue());
            }
        }
    }

    private LocalDateInterval limiteerTotOpper(LocalDateInterval periode, Opper opper, boolean isApo) {
        LocalDateInterval interval = opper.getActualInterval().overlap(periode);
        if (isApo) {
            interval = new LocalDateInterval(periode.getStart().withDayOfMonth(1), periode.getEnd().dayOfMonth().withMaximumValue());
            LocalDateInterval opdrachtPeriode = new LocalDateInterval(opper.getOpdracht().getBeginDatum(), opper.getOpdracht().getEindDatum());
            interval = interval.overlap(opdrachtPeriode);
        }
        return interval;
    }

    private List<RekenHoofd> cleanNulResultaten(List<RekenHoofd> rekenHoofdenPersoon, Map<Integer, Boolean> opdrachtIdToNulResultaat) {
        List<RekenHoofd> cleaned = new ArrayList<>();

        ListMultimap<Integer, RekenHoofd> opdrachtIdToRekenHoofden = RekenResultaatUtil.mapOpdrachtIdToRekenHoofden(rekenHoofdenPersoon);

        for (Integer opdrachtid : opdrachtIdToRekenHoofden.keySet()) {
            boolean nulResultaat = opdrachtIdToNulResultaat.get(opdrachtid);
            List<RekenHoofd> rekenHoofden = opdrachtIdToRekenHoofden.get(opdrachtid);
            boolean nulAanwezig = false;
            boolean nietNulAanwezig = false;
            for (RekenHoofd hoofd : rekenHoofden) {
                for (RekenLijn lijn : hoofd.getRekenLijnen()) {
                    for (RekenBedrag rekenBedrag : lijn.getRekenBedragen()) {
                        boolean rekenBedragZeroOpslaan = rekenBedragZeroOpslaan(lijn.getAardKodeExtensie(), rekenBedrag.getBedragType());
                        nulAanwezig = nulAanwezig || (rekenBedrag.getBedrag().signum() == 0 && !rekenBedragZeroOpslaan);
                        nietNulAanwezig = nietNulAanwezig || rekenBedrag.getBedrag().signum() != 0;
                        if (nulAanwezig && nietNulAanwezig) {
                            break;
                        }
                    }
                }
            }

            if (nulAanwezig && (nietNulAanwezig || !nulResultaat)) {
                for (RekenHoofd hoofd : rekenHoofden) {
                    Set<RekenLijn> lijnen = new HashSet<>();
                    for (RekenLijn lijn : hoofd.getRekenLijnen()) {
                        Set<RekenBedrag> rekenBedragen =
                                lijn.getRekenBedragen()
                                        .stream()
                                        .filter(x -> x.getBedrag().signum() != 0 || rekenBedragZeroOpslaan(lijn.getAardKodeExtensie(), x.getBedragType()))
                                        .collect(Collectors.toSet());
                        if (!rekenBedragen.isEmpty()) {
                            lijn.setRekenBedragen(rekenBedragen);
                            lijnen.add(lijn);
                        }
                    }
                    if (!lijnen.isEmpty()) {
                        hoofd.setRekenLijnen(lijnen);
                        cleaned.add(hoofd);
                    }
                }
            } else {
                cleaned.addAll(rekenHoofden);
            }
        }
        return cleaned;
    }

